sequence.script:
// -----------------------------
// Get initial payload
// -----------------------------
var initPayload = mc.getProperty("inputData");
if (typeof initPayload === "string") {
    initPayload = JSON.parse(initPayload);
}

var payload = mc.getPayloadJSON();

// -----------------------------
// Extract assignment & lossItem (order-independent)
// -----------------------------
var assignment = null;
var lossItem = null;

for (var i = 0; i < payload.length; i++) {
    var item = payload[i];

    if (item.assignmentResponse) {
        assignment = item.assignmentResponse;
    }

    if (item.lossitemsResponse && item.lossitemsResponse.length > 0) {
        lossItem = item.lossitemsResponse[0];
    }
}

// -----------------------------
// Safety checks
// -----------------------------
if (!assignment) {
    throw "assignmentResponse not found in payload";
}

if (!lossItem) {
    throw "lossitemsResponse not found in payload";
}

// -----------------------------
// Set property
// -----------------------------
mc.setProperty("lossItemIdentifier", lossItem.lossItemIdentifier);

// -----------------------------
// Deep copy inputData
// -----------------------------
var updatedPayload = JSON.parse(JSON.stringify(initPayload));

// -----------------------------
// DW: update case .assessment
// -----------------------------
if (updatedPayload.assessment) {

    var a = updatedPayload.assessment;

    // mutate existing object (DO NOT replace)
    updatedPayload.assessment.netPayableAmount =
        (a.assessedLossAmount || 0)
        - (a.depreciationAmount || 0)
        - (a.deductibleAmount || 0);
}

// -----------------------------
// DW: update case .inspectionOutcome
// -----------------------------
if (updatedPayload.inspectionOutcome) {

    var io = updatedPayload.inspectionOutcome;

    // mutate existing object (DO NOT replace)
    io.recommendation =
        io.recommendation || "PROCEED_WITH_SETTLEMENT";

    io.remarks =
        io.remarks || "Repairable damage; recommend cashless repair";
}

// -----------------------------
// Date calculation (now + 1 day)
// -----------------------------
var now = new Date();
now.setDate(now.getDate() + 1);

var inspectionDate = new Date(now.getTime()).toISOString();

// -----------------------------
// Construct final response
// -----------------------------
var result = {

    inspectionType: "FIELD_SURVEY",
    inspectionStatus: "APPROVED",

    adjusterDetails: {
        adjusterId: assignment.adjusterId,
        adjusterType: "FIELD_SURVEYOR",
        assignedDate: assignment.assignedDate,
        inspectionDate: inspectionDate
    },

    lossItemReference: {
        lossItemIdentifier: lossItem.lossItemIdentifier,
        insurableObjectIdentifier: lossItem.insurableObjectIdentifier,
        coverageIdentifier: lossItem.coverageIdentifier,
        lossTypeCode: lossItem.lossTypeCode,
        damageCategory: lossItem.damageCategory
    },

    // Directly reuse updated payload sections (DW behavior)
    inspectionFindings: updatedPayload.inspectionFindings,
    assessment: updatedPayload.assessment,

    inspectionOutcome: updatedPayload.inspectionOutcome || {
        recommendation: "PROCEED_WITH_SETTLEMENT",
        remarks: "Repairable damage; recommend cashless repair"
    }
};

// -----------------------------
// Set final payload
// -----------------------------
mc.setPayloadJSON(result);
